fn sum(nums: &Vec<i32>) -> i32 {
    nums.iter().sum()
}

fn add_element(nums: &mut Vec<i32>, val: i32) {
    nums.push(val);
}

fn main() {
    let mut nums = vec![1, 2, 3];
    println!("{}", sum(&nums));  // 6

    add_element(&mut nums, 4);
    println!("{:?}", nums);  // [1, 2, 3, 4]
}

