fn min_max(nums: &Vec<i32>) -> (i32, i32) {
    let mut mn = nums[0];
    let mut mx = nums[0];
    for &x in nums {
        if x < mn { mn = x; }
        if x > mx { mx = x; }
    }
    (mn, mx)
}

fn main() {
    let nums = vec![3, 1, 4, 1, 5, 9];
    let (lo, hi) = min_max(&nums);
    println!("{} {}", lo, hi);  // 1 9
}

